import React, { useState, useEffect } from 'react';
import './styles/App.css';
import RegistrationForm from './components/RegistrationForm';
import Gallery from './components/Gallery';
import CountdownTimer from './components/CountdownTimer';
import HeroSection from './components/HeroSection';
import InfoSection from './components/InfoSection';
import 'bootstrap/dist/css/bootstrap.min.css';



function App() {
  const [showForm, setShowForm] = useState(true);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      const isScrolled = window.scrollY > 100;
      if (isScrolled !== scrolled) {
        setScrolled(isScrolled);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [scrolled]);

  const handleTimerComplete = () => {
    setShowForm(false);
  };

  return (
    <div className="App">
      <nav className={`navbars ${scrolled ? 'navbars-scrolled' : ''}`}>
        <div className="navs-container">
          <h1 className="logos">TechConf 2024</h1>
          <ul className="navs-menu">
            <li><a href="#home">Inicio</a></li>
            <li><a href="#info">Información</a></li>
            <li><a href="#gallery">Galería</a></li>
            <li><a href="#register">Registro</a></li>
          </ul>
        </div>
      </nav>

      <section id="home">
        <HeroSection />
      </section>

      <section id="info">
        <InfoSection />
      </section>

      <section id="gallery">
        <Gallery />
      </section>

      <section id="register" className="register-section">
        <div className="container">
          <h2 className="section-title">Regístrate Ahora</h2>
          <CountdownTimer onComplete={handleTimerComplete} />
          {showForm ? (
            <RegistrationForm />
          ) : (
            <div className="form-expired">
              <h3>⏰ El tiempo de registro ha expirado</h3>
              <p>El período de registro para este evento ha finalizado.</p>
            </div>
          )}
        </div>
      </section>

      <footer className="footer">
        <p>&copy; 2024 TechConf. Todos los derechos reservados.</p>
      </footer>
    </div>
  );
}

export default App;
